{
  "summary": "This paper introduces MGSM, a novel multilingual arithmetic reasoning benchmark with manually translated grade-school math problems across ten typologically diverse languages. It evaluates large language models using various prompting strategies, demonstrating emergent multilingual multi-step reasoning abilities, especially with chain-of-thought prompting, and extends findings to other reasoning tasks like commonsense and semantic judgment.",
  "strengths": [
    {
      "point": "Introduction of a novel multilingual arithmetic reasoning benchmark (MGSM) with manual translations.",
      "evidence": "MGSM consists of 250 grade-school math problems translated into ten diverse languages, providing a challenging testbed for multilingual multi-step reasoning."
    },
    {
      "point": "Demonstration of emergent multilingual multi-step reasoning abilities in large language models.",
      "evidence": "The large proprietary LLM achieves over 40% accuracy across all languages, including underrepresented ones, with chain-of-thought prompting significantly improving performance."
    },
    {
      "point": "Insight that English chain-of-thought prompting often matches or outperforms native language prompting.",
      "evidence": "EN-CoT prompting frequently yields better results than NATIVE-CoT, suggesting English intermediate reasoning steps are a strong baseline for multilingual reasoning."
    },
    {
      "point": "Extension of multilingual reasoning evaluation beyond arithmetic to commonsense and semantic judgment tasks.",
      "evidence": "The LLM-540B sets a new state-of-the-art on XCOPA and achieves competitive results on XL-WiC, demonstrating generalizability of multilingual reasoning abilities."
    },
    {
      "point": "Systematic evaluation of different prompting and exemplar selection strategies.",
      "evidence": "The paper compares direct prediction, native CoT, English CoT, and translate-then-English CoT prompting, as well as native, English, and multilingual exemplars."
    }
  ],
  "weaknesses": [
    {
      "point": "Insufficient discussion and comparison to prior multilingual reasoning benchmarks.",
      "evidence": "The paper does not adequately position MGSM relative to existing multilingual math word problem or QA datasets with reasoning components."
    },
    {
      "point": "Lack of detailed justification for the selection of the ten languages.",
      "evidence": "Beyond typological diversity, the paper does not explain representativeness regarding script, morphology, or syntactic complexity."
    },
    {
      "point": "Limited transparency about the manual translation process and quality control.",
      "evidence": "No details on translator expertise, quality assurance, or handling of translation ambiguities are provided, raising concerns about benchmark consistency."
    },
    {
      "point": "Evaluation omits comparisons to strong multilingual pretrained models fine-tuned or prompted on MGSM.",
      "evidence": "Models like mT5 or XLM-R variants are not included, making it unclear if results generalize beyond large English-centric LLMs."
    },
    {
      "point": "Lack of analysis explaining why English CoT prompting outperforms native language CoT prompting.",
      "evidence": "No ablations or qualitative studies are presented to clarify whether this is due to training biases, translation artifacts, or prompt design."
    },
    {
      "point": "Insufficient detail on few-shot exemplar selection criteria.",
      "evidence": "The paper does not specify how exemplars were chosen per language or problem type, limiting assessment of fairness and replicability."
    },
    {
      "point": "Evaluation metrics are limited to accuracy without deeper reasoning step analysis.",
      "evidence": "No metrics on intermediate step correctness, coherence, or detailed error analysis are provided."
    },
    {
      "point": "Proprietary LLM details are not disclosed, hindering reproducibility.",
      "evidence": "Architecture, training data, training procedures, and inference settings for the large LLM are missing."
    },
    {
      "point": "Prompt templates and exemplar examples are not fully provided.",
      "evidence": "Exact prompts and instructions for different prompting strategies are absent, limiting reproducibility."
    },
    {
      "point": "Ambiguity in how language frequency in training data was measured.",
      "evidence": "The paper does not clarify the methodology for estimating language frequency, complicating interpretation of related conclusions."
    },
    {
      "point": "No discussion on handling code-switching or mixed-language inputs.",
      "evidence": "The study focuses solely on monolingual inputs, limiting applicability to real-world multilingual scenarios."
    },
    {
      "point": "Limited task scope focusing mainly on arithmetic and selected reasoning types.",
      "evidence": "Other complex reasoning domains like logical deduction, temporal, or multi-modal reasoning are not addressed."
    },
    {
      "point": "Generalisability to truly low-resource or endangered languages is not explored.",
      "evidence": "Languages with very limited training data or different scripts beyond the tested set are not evaluated."
    },
    {
      "point": "No analysis of the effect of script or orthographic differences on reasoning performance.",
      "evidence": "Despite diverse scripts in MGSM languages, the impact of script complexity is not studied."
    },
    {
      "point": "Presentation of results lacks granular per-language analysis and error patterns.",
      "evidence": "Aggregated results obscure specific language challenges or strengths."
    }
  ],
  "questions": [
    {
      "question": "How does MGSM compare quantitatively and qualitatively to existing multilingual reasoning benchmarks?",
      "motivation": "Clarifying this would strengthen the novelty claim and contextualize the benchmark's contribution."
    },
    {
      "question": "What factors cause English CoT prompting to outperform native language CoT prompting?",
      "motivation": "Understanding this could inform better prompt design and reveal model biases or limitations."
    },
    {
      "question": "How would strong multilingual pretrained models like mT5 or XLM-R perform on MGSM with similar prompting strategies?",
      "motivation": "This would clarify whether observed multilingual reasoning abilities are unique to large English-centric LLMs or generalize across architectures."
    },
    {
      "question": "What is the impact of translation quality and potential ambiguities on reasoning performance across languages?",
      "motivation": "Ensuring benchmark fairness and consistency requires understanding translation effects."
    },
    {
      "question": "How do script and orthographic differences affect multilingual reasoning and prompting effectiveness?",
      "motivation": "Insights here could guide model and benchmark design for diverse languages."
    },
    {
      "question": "Can the benchmark and methods be extended to handle code-switching or mixed-language inputs common in multilingual contexts?",
      "motivation": "Addressing this would increase real-world applicability of multilingual reasoning evaluations."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
